import { useState } from 'react'; // <--- 1. Імпортуємо useState
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import './App.css';
import RegisterPage from './pages/register';
import LoginPage from './pages/login';
import MainPage from './pages/main-page';

function App() {
    // 2. Створюємо стан для відстеження авторизації
    const [isAuthenticated, setIsAuthenticated] = useState(false); 

    const registerUser = () => {
        // Логіка реєстрації...
        // ... Після успішної реєстрації встановлюємо стан
        setIsAuthenticated(true); 
    };

    const loginUser = () => {
        // Логіка логіну...
        // ... Після успішного логіну встановлюємо стан
        setIsAuthenticated(true); 
    };

    // (Видаляємо функцію getMainPage, вона більше не потрібна)

    return (
        <Router>
            <div className="App">
                <Routes>
                    <Route 
                        path="/register" 
                        element={
                            // 3. Якщо авторизований, перенаправляємо на "/" (де буде MainPage)
                            isAuthenticated 
                                ? <Navigate to="/" replace /> 
                                : <RegisterPage onRegister={registerUser} />
                        } 
                    />
                    <Route 
                        path="/login" 
                        element={
                            // 3. Якщо авторизований, перенаправляємо на "/"
                            isAuthenticated 
                                ? <Navigate to="/" replace /> 
                                : <LoginPage onLogin={loginUser} />
                        } 
                    />

                    {/* 4. Захищений маршрут для MainPage */}
                    <Route 
                        path="/" 
                        element={
                            // Якщо авторизований, показуємо MainPage
                            isAuthenticated 
                                ? <MainPage /> 
                                // Якщо не авторизований, перенаправляємо на сторінку логіну
                                : <Navigate to="/login" replace />
                        } 
                    />
                </Routes>
            </div>
        </Router>
    );
}

export default App;
